+import Yoga from 'yoga-layout';
+import {type DOMElement, type DOMNode} from './dom.js';
+
+type Track =
+	| {type: 'fixed'; value: number}
+	| {type: 'fr'; value: number}
+	| {type: 'auto'}
+	| {type: 'minmax'; min: number; max: number | {fr: number}};
+
+type Placement = {start?: number; end?: number};
+
+const parseTracks = (template: string | undefined): Track[] => {
+	if (!template) return [{type: 'auto'}];
+	return template.match(/minmax\\([^)]*\\)|[^\\s]+/g)?.map(token => {
+		if (token === 'auto') return {type: 'auto'};
+		if (token.startsWith('minmax(')) {
+			const [min, max] = token.slice(7, -1).split(',').map(part => part.trim());
+			const fr = max.endsWith('fr') ? Number.parseFloat(max) : undefined;
+			return {type: 'minmax', min: Number.parseFloat(min), max: fr === undefined ? Number.parseFloat(max) : {fr}};
+		}
+		if (token.endsWith('fr')) return {type: 'fr', value: Number.parseFloat(token)};
+		return {type: 'fixed', value: Number.parseFloat(token)};
+	}) ?? [{type: 'auto'}];
+};
+
+const parsePlacement = (value: number | string | undefined): Placement => {
+	if (typeof value === 'number') return {start: value};
+	if (!value) return {};
+	const parts = value.split('/').map(part => Number.parseInt(part.trim(), 10));
+	return parts.length === 1 ? {start: parts[0]} : {start: parts[0], end: parts[1]};
+};
+
+const sizeTracks = (tracks: Track[], available: number, gap: number, intrinsic: number[]): number[] => {
+	const sizes = tracks.map((track, index) => {
+		if (track.type === 'fixed') return track.value;
+		if (track.type === 'auto') return intrinsic[index] ?? 0;
+		if (track.type === 'minmax') return Math.max(track.min, intrinsic[index] ?? 0);
+		return 0;
+	});
+	const frTracks = tracks.flatMap((track, index) =>
+		track.type === 'fr' ? [{index, value: track.value}] : track.type === 'minmax' && typeof track.max !== 'number' ? [{index, value: track.max.fr}] : [],
+	);
+	const remaining = Math.max(0, available - sizes.reduce((sum, size) => sum + size, 0) - Math.max(0, tracks.length - 1) * gap);
+	const totalFr = frTracks.reduce((sum, track) => sum + track.value, 0);
+	for (const track of frTracks) sizes[track.index] += totalFr ? remaining * track.value / totalFr : 0;
+	return sizes.map((size, index) => {
+		const track = tracks[index];
+		return track.type === 'minmax' && typeof track.max === 'number' ? Math.min(size, track.max) : size;
+	});
+};
+
+const gridChildren = (node: DOMElement): DOMElement[] => node.childNodes.filter((child): child is DOMElement => Boolean((child as DOMNode).yogaNode));
+
+const resetGridLayout = (node: DOMElement): void => {
+	for (const child of node.childNodes) {
+		if (!('nodeName' in child) || !child.yogaNode) continue;
+		child.yogaNode.setPositionType(Yoga.POSITION_TYPE_RELATIVE);
+		child.yogaNode.setPosition(Yoga.EDGE_LEFT, 0);
+		child.yogaNode.setPosition(Yoga.EDGE_TOP, 0);
+		child.yogaNode.setWidthAuto();
+		child.yogaNode.setHeightAuto();
+		if (child.style.width !== undefined) child.yogaNode.setWidth(child.style.width as number);
+		if (child.style.height !== undefined) child.yogaNode.setHeight(child.style.height as number);
+		resetGridLayout(child as DOMElement);
+	}
+};
+
+const layoutGrid = (node: DOMElement): void => {
+	for (const child of gridChildren(node)) layoutGrid(child);
+	if (node.style.display !== 'grid' || !node.yogaNode) return;
+
+	const children = gridChildren(node);
+	const columns = parseTracks(node.style.gridTemplateColumns);
+	let rows = parseTracks(node.style.gridTemplateRows);
+	const columnGap = node.style.columnGap ?? node.style.gap ?? 0;
+	const rowGap = node.style.rowGap ?? node.style.gap ?? 0;
+	const layout = node.yogaNode.getComputedLayout();
+	const contentWidth = layout.width - node.yogaNode.getComputedPadding(Yoga.EDGE_LEFT) - node.yogaNode.getComputedPadding(Yoga.EDGE_RIGHT) - node.yogaNode.getComputedBorder(Yoga.EDGE_LEFT) - node.yogaNode.getComputedBorder(Yoga.EDGE_RIGHT);
+	const contentHeight = layout.height - node.yogaNode.getComputedPadding(Yoga.EDGE_TOP) - node.yogaNode.getComputedPadding(Yoga.EDGE_BOTTOM) - node.yogaNode.getComputedBorder(Yoga.EDGE_TOP) - node.yogaNode.getComputedBorder(Yoga.EDGE_BOTTOM);
+	const occupied = new Set<string>();
+	const placements: Array<{child: DOMElement; column: Placement; row: Placement}> = [];
+	let cursorRow = 1;
