+	for (const child of children) {
+		const column = parsePlacement(child.style.gridColumn);
+		const row = parsePlacement(child.style.gridRow);
+		const columnSpan = Math.max(1, (column.end ?? (column.start ?? 1) + 1) - (column.start ?? 1));
+		const rowSpan = Math.max(1, (row.end ?? (row.start ?? 1) + 1) - (row.start ?? 1));
