+	while (rows.length < rowCount) rows.push({type: 'auto'});
+	const columnIntrinsic = columns.map(() => 0);
+	const rowIntrinsic = rows.map(() => 0);
+	for (const {child, column, row} of placements) {
+		const childLayout = child.yogaNode!.getComputedLayout();
+		if (column.end! - column.start! === 1) columnIntrinsic[column.start! - 1] = Math.max(columnIntrinsic[column.start! - 1], childLayout.width);
+		if (row.end! - row.start! === 1) rowIntrinsic[row.start! - 1] = Math.max(rowIntrinsic[row.start! - 1], childLayout.height);
+	}
+	const columnSizes = sizeTracks(columns, contentWidth, columnGap, columnIntrinsic);
+	const naturalHeight = rowIntrinsic.reduce((sum, size) => sum + size, 0) + Math.max(0, rows.length - 1) * rowGap;
+	const rowSizes = sizeTracks(rows, node.style.height === undefined ? naturalHeight : contentHeight, rowGap, rowIntrinsic);
+	const left = (index: number) => columnSizes.slice(0, index).reduce((sum, size) => sum + size, 0) + index * columnGap + node.yogaNode!.getComputedPadding(Yoga.EDGE_LEFT) + node.yogaNode!.getComputedBorder(Yoga.EDGE_LEFT);
+	const top = (index: number) => rowSizes.slice(0, index).reduce((sum, size) => sum + size, 0) + index * rowGap + node.yogaNode!.getComputedPadding(Yoga.EDGE_TOP) + node.yogaNode!.getComputedBorder(Yoga.EDGE_TOP);
+	for (const {child, column, row} of placements) {
+		const startColumn = column.start! - 1; const endColumn = column.end! - 1;
+		const startRow = row.start! - 1; const endRow = row.end! - 1;
+		child.yogaNode!.setPositionType(Yoga.POSITION_TYPE_ABSOLUTE);
+		child.yogaNode!.setPosition(Yoga.EDGE_LEFT, left(startColumn));
+		child.yogaNode!.setPosition(Yoga.EDGE_TOP, top(startRow));
+		child.yogaNode!.setWidth(columnSizes.slice(startColumn, endColumn).reduce((sum, size) => sum + size, 0) + (endColumn - startColumn - 1) * columnGap);
+		child.yogaNode!.setHeight(rowSizes.slice(startRow, endRow).reduce((sum, size) => sum + size, 0) + (endRow - startRow - 1) * rowGap);
+	}
+	if (node.style.height === undefined) node.yogaNode.setHeight(naturalHeight + node.yogaNode.getComputedPadding(Yoga.EDGE_TOP) + node.yogaNode.getComputedPadding(Yoga.EDGE_BOTTOM) + node.yogaNode.getComputedBorder(Yoga.EDGE_TOP) + node.yogaNode.getComputedBorder(Yoga.EDGE_BOTTOM));
+};
+
+export const calculateGridLayout = (root: DOMElement): void => {
